// ─── FIREBASE HELPERS (loaded dynamically when config is present) ─────────────
let _db = null;
async function getDb() {
  if (_db) return _db;
  const { initializeApp } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js");
  const { getFirestore } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  _db = getFirestore(initializeApp(firebaseConfig));
  return _db;
}
async function fbGetClients() {
  const { collection, getDocs } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  const snap = await getDocs(collection(db, "clients"));
  return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}
async function fbSaveClient(client) {
  const { doc, setDoc } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  await setDoc(doc(db, "clients", String(client.id)), client);
}
async function fbDeleteClient(id) {
  const { doc, deleteDoc } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  await deleteDoc(doc(db, "clients", String(id)));
}
async function fbGetTrainer() {
  const { doc, getDoc } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  const snap = await getDoc(doc(db, "settings", "trainer"));
  return snap.exists() ? snap.data() : DEFAULT_TRAINER;
}
async function fbSaveTrainer(t) {
  const { doc, setDoc } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  await setDoc(doc(db, "settings", "trainer"), t);
}
async function fbSubscribeClients(cb) {
  const { collection, onSnapshot } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  return onSnapshot(collection(db, "clients"), snap => cb(snap.docs.map(d => ({ id: d.id, ...d.data() }))));
}
async function fbSubscribeClient(id, cb) {
  const { doc, onSnapshot } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  return onSnapshot(doc(db, "clients", String(id)), snap => { if (snap.exists()) cb({ id: snap.id, ...snap.data() }); });
}
async function seedIfEmpty() {
  const { collection, getDocs, doc, setDoc } = await import("https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js");
  const db = await getDb();
  const snap = await getDocs(collection(db, "clients"));
  if (!snap.empty) return;
  for (const client of defaultClients) await setDoc(doc(db, "clients", String(client.id)), client);
  await setDoc(doc(db, "settings", "trainer"), DEFAULT_TRAINER);
}

