const db_deleteClient = (id) => { if (USE_FIREBASE) return fbDeleteClient(id); lsSaveClients(lsGetClients().filter(c => c.id !== id)); return Promise.resolve(); };
const db_getTrainer = () => USE_FIREBASE ? fbGetTrainer() : Promise.resolve(lsGetTrainer());
const db_saveTrainer = (t) => { if (USE_FIREBASE) return fbSaveTrainer(t); lsSaveTrainer(t); return Promise.resolve(); };

