// ─── SETTINGS VIEW ────────────────────────────────────────────────────────────
function SettingsView({ creds, onSave, onBack }) {
  const [form, setForm] = useState({ name: creds.name, email: creds.email, currentPassword: "", newPassword: "", confirmPassword: "" });
  const [status, setStatus] = useState(null); // "success" | "error" | null
  const [msg, setMsg] = useState("");

  const handleSave = () => {
    setStatus(null);
    // Validate current password
    if (form.currentPassword !== creds.password) {
      setStatus("error"); setMsg("Current password is incorrect."); return;
    }
    if (form.newPassword && form.newPassword !== form.confirmPassword) {
      setStatus("error"); setMsg("New passwords don\'t match."); return;
    }
    if (form.newPassword && form.newPassword.length < 6) {
      setStatus("error"); setMsg("New password must be at least 6 characters."); return;
    }
    const updated = {
      name: form.name || creds.name,
      email: form.email || creds.email,
      password: form.newPassword || creds.password
    };
    onSave(updated);
    setStatus("success");
    setMsg(form.newPassword ? "Password updated successfully! ✓" : "Profile updated successfully! ✓");
    setForm(f => ({ ...f, currentPassword: "", newPassword: "", confirmPassword: "" }));
  };

  return (
    <div>
      <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 6, color: "white" }}>⚙️ Settings</div>
      <div style={{ fontSize: 13, color: "#475569", marginBottom: 24 }}>Update your trainer profile and password</div>

      {/* Profile section */}
      <div style={{ background: "rgba(15,23,42,0.8)", border: "1px solid rgba(99,102,241,0.15)", borderRadius: 16, padding: 18, marginBottom: 16 }}>
        <div style={{ fontSize: 12, color: "#6366f1", textTransform: "uppercase", letterSpacing: 1, fontWeight: 700, marginBottom: 16 }}>Trainer Profile</div>
        <div style={{ marginBottom: 14 }}>
          <label style={{ fontSize: 11, color: "#475569", textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 7 }}>Display Name</label>
          <input style={{ ...inp(), fontSize: 15, padding: "13px 14px" }} value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Coach Anubhav" />
        </div>
        <div>
          <label style={{ fontSize: 11, color: "#475569", textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 7 }}>Login Email</label>
          <input type="email" style={{ ...inp(), fontSize: 15, padding: "13px 14px" }} value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
        </div>
      </div>

      {/* Password section */}
      <div style={{ background: "rgba(15,23,42,0.8)", border: "1px solid rgba(99,102,241,0.15)", borderRadius: 16, padding: 18, marginBottom: 16 }}>
        <div style={{ fontSize: 12, color: "#6366f1", textTransform: "uppercase", letterSpacing: 1, fontWeight: 700, marginBottom: 16 }}>Change Password</div>
        <div style={{ marginBottom: 14 }}>
          <label style={{ fontSize: 11, color: "#475569", textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 7 }}>Current Password</label>
          <input type="password" style={{ ...inp(), fontSize: 15, padding: "13px 14px" }} value={form.currentPassword} onChange={e => setForm({ ...form, currentPassword: e.target.value })} placeholder="Enter current password" />
        </div>
        <div style={{ marginBottom: 14 }}>
          <label style={{ fontSize: 11, color: "#475569", textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 7 }}>New Password</label>
          <input type="password" style={{ ...inp(), fontSize: 15, padding: "13px 14px" }} value={form.newPassword} onChange={e => setForm({ ...form, newPassword: e.target.value })} placeholder="Leave blank to keep current" />
        </div>
        <div>
          <label style={{ fontSize: 11, color: "#475569", textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 7 }}>Confirm New Password</label>
          <input type="password" style={{ ...inp(), fontSize: 15, padding: "13px 14px" }} value={form.confirmPassword} onChange={e => setForm({ ...form, confirmPassword: e.target.value })} placeholder="Repeat new password" />
        </div>
      </div>

      {/* Status message */}
      {status && (
        <div style={{ background: status === "success" ? "rgba(16,185,129,0.1)" : "rgba(239,68,68,0.1)", border: "1px solid " + (status === "success" ? "rgba(16,185,129,0.4)" : "rgba(239,68,68,0.4)"), color: status === "success" ? "#10b981" : "#f87171", borderRadius: 12, padding: "12px 16px", fontSize: 14, marginBottom: 16, fontWeight: 600 }}>
          {msg}
        </div>
      )}

      {/* Save button */}
      <div style={{ position: "sticky", bottom: 16 }}>
        <button onClick={handleSave}
          style={{ width: "100%", background: "linear-gradient(135deg,#6366f1,#8b5cf6)", border: "none", color: "white", borderRadius: 16, padding: "16px", fontWeight: 700, fontSize: 16, cursor: "pointer", fontFamily: "inherit", boxShadow: "0 4px 20px rgba(99,102,241,0.4)" }}>
          Save Changes
        </button>
      </div>
    </div>
  );
}

